package com.weeklycommit.ai.controller;

import com.weeklycommit.ai.dto.AiFeedbackRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.dto.CommitLintRequest;
import com.weeklycommit.ai.dto.CommitLintResponse;
import com.weeklycommit.ai.dto.ManagerAiSummaryResponse;
import com.weeklycommit.ai.dto.RcdoSuggestRequest;
import com.weeklycommit.ai.dto.RcdoSuggestResponse;
import com.weeklycommit.ai.dto.ReconcileAssistRequest;
import com.weeklycommit.ai.dto.ReconcileAssistResponse;
import com.weeklycommit.ai.dto.RiskSignalResponse.PlanRiskSignals;
import com.weeklycommit.ai.provider.AiProvider;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.service.CommitDraftAssistService;
import com.weeklycommit.ai.service.CommitLintService;
import com.weeklycommit.ai.service.ManagerAiSummaryService;
import com.weeklycommit.ai.service.RcdoSuggestService;
import com.weeklycommit.ai.service.RiskDetectionService;
import com.weeklycommit.ai.service.ReconcileAssistService;
import com.weeklycommit.ai.service.AiSuggestionService;
import jakarta.validation.Valid;
import java.time.LocalDate;
import java.util.UUID;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for AI-powered commit assistance, linting, RCDO suggestions,
 * risk detection, reconciliation assistance, and manager summaries.
 *
 * <p>
 * All endpoints degrade gracefully: when AI is disabled or unavailable the
 * response includes {@code aiAvailable: false} and no error is returned. Core
 * workflow is never blocked by AI unavailability.
 */
@RestController
public class AiController {

	private final CommitDraftAssistService draftAssistService;
	private final CommitLintService lintService;
	private final RcdoSuggestService rcdoSuggestService;
	private final RiskDetectionService riskDetectionService;
	private final ReconcileAssistService reconcileAssistService;
	private final ManagerAiSummaryService managerSummaryService;
	private final AiSuggestionService suggestionService;
	private final AiProviderRegistry providerRegistry;

	public AiController(CommitDraftAssistService draftAssistService, CommitLintService lintService,
			RcdoSuggestService rcdoSuggestService, RiskDetectionService riskDetectionService,
			ReconcileAssistService reconcileAssistService, ManagerAiSummaryService managerSummaryService,
			AiSuggestionService suggestionService, AiProviderRegistry providerRegistry) {
		this.draftAssistService = draftAssistService;
		this.lintService = lintService;
		this.rcdoSuggestService = rcdoSuggestService;
		this.riskDetectionService = riskDetectionService;
		this.reconcileAssistService = reconcileAssistService;
		this.managerSummaryService = managerSummaryService;
		this.suggestionService = suggestionService;
		this.providerRegistry = providerRegistry;
	}

	// -------------------------------------------------------------------------
	// Capability 1: Commit draft assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns suggestions for improving a commit draft (title, description, success
	 * criteria, estimate). Suggestions are editable proposals — never auto-applied.
	 */
	@PostMapping("/api/ai/commit-draft-assist")
	public ResponseEntity<CommitDraftAssistResponse> commitDraftAssist(
			@Valid @RequestBody CommitDraftAssistRequest request) {
		return ResponseEntity.ok(draftAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 2: Commit quality lint
	// -------------------------------------------------------------------------

	/**
	 * Runs commit quality lint for a plan. Returns {@code hardValidation} (blocks
	 * lock) and {@code softGuidance} (informational) messages.
	 */
	@PostMapping("/api/ai/commit-lint")
	public ResponseEntity<CommitLintResponse> commitLint(@Valid @RequestBody CommitLintRequest request) {
		return ResponseEntity.ok(lintService.lint(request));
	}

	// -------------------------------------------------------------------------
	// Capability 3: RCDO link suggestion
	// -------------------------------------------------------------------------

	/**
	 * Suggests a primary RCDO node for a commit draft. Only surfaced when
	 * confidence &ge; 0.7. Never auto-links.
	 */
	@PostMapping("/api/ai/rcdo-suggest")
	public ResponseEntity<RcdoSuggestResponse> rcdoSuggest(@Valid @RequestBody RcdoSuggestRequest request) {
		return ResponseEntity.ok(rcdoSuggestService.suggest(request));
	}

	// -------------------------------------------------------------------------
	// Capability 4: Risk signals
	// -------------------------------------------------------------------------

	/**
	 * Returns current risk signals for the given plan. Hidden from peers — only the
	 * plan owner and their manager should call this endpoint.
	 */
	@GetMapping("/api/plans/{id}/risk-signals")
	public ResponseEntity<PlanRiskSignals> getRiskSignals(@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		if (callerId == null) {
			return ResponseEntity.badRequest().build();
		}
		return ResponseEntity.ok(riskDetectionService.getRiskSignals(id, callerId));
	}

	// -------------------------------------------------------------------------
	// Capability 5: Reconciliation assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns reconciliation assistance: likely outcomes, draft summary, and
	 * carry-forward recommendations for a plan entering the reconcile phase.
	 */
	@PostMapping("/api/ai/reconcile-assist")
	public ResponseEntity<ReconcileAssistResponse> reconcileAssist(@Valid @RequestBody ReconcileAssistRequest request) {
		return ResponseEntity.ok(reconcileAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 6: Manager team AI summary
	// -------------------------------------------------------------------------

	/**
	 * Returns the AI-generated team summary for the given week. Only accessible to
	 * managers.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/ai-summary")
	public ResponseEntity<ManagerAiSummaryResponse> getTeamAiSummary(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		return ResponseEntity.ok(managerSummaryService.getSummary(id, weekStart, callerId));
	}

	// -------------------------------------------------------------------------
	// AI Status
	// -------------------------------------------------------------------------

	/**
	 * Returns the current AI provider status: enabled, provider name/version,
	 * availability. Useful for ops dashboards and frontend feature checks.
	 */
	@GetMapping("/api/ai/status")
	public ResponseEntity<java.util.Map<String, Object>> getAiStatus() {
		java.util.Optional<AiProvider> active = providerRegistry.getActiveProvider();
		java.util.Map<String, Object> status = new java.util.LinkedHashMap<>();
		status.put("aiEnabled", providerRegistry.isAiEnabled());
		status.put("providerName", active.map(AiProvider::getName).orElse("none"));
		status.put("providerVersion", active.map(AiProvider::getVersion).orElse("none"));
		status.put("available", active.map(AiProvider::isAvailable).orElse(false));
		return ResponseEntity.ok(status);
	}

	// -------------------------------------------------------------------------
	// Feedback
	// -------------------------------------------------------------------------

	/**
	 * Records user feedback (ACCEPTED / DISMISSED / EDITED) on an AI suggestion.
	 */
	@PostMapping("/api/ai/feedback")
	public ResponseEntity<Void> recordFeedback(@Valid @RequestBody AiFeedbackRequest request) {
		suggestionService.recordFeedback(request);
		return ResponseEntity.status(HttpStatus.CREATED).build();
	}
}

package com.weeklycommit.ai.provider;

/**
 * Strategy interface for AI suggestion providers.
 *
 * <p>
 * Implementations must be idempotent and must never throw unchecked exceptions
 * that would bubble up to the caller — all errors must be surfaced via
 * {@link AiSuggestionResult#unavailable()}.
 */
public interface AiProvider {

	/** Unique, human-readable name for this provider (e.g., "stub", "openai"). */
	String getName();

	/** Model/version identifier used for audit and reproducibility. */
	String getVersion();

	/**
	 * Returns {@code true} when the provider is reachable and ready.
	 *
	 * <p>
	 * This is a fast health check; implementations should cache results and avoid
	 * expensive round-trips on every call.
	 */
	boolean isAvailable();

	/**
	 * Generates a suggestion for the given context.
	 *
	 * <p>
	 * Must never throw. Returns {@link AiSuggestionResult#unavailable()} if the
	 * provider is down or an internal error occurs.
	 *
	 * @param context
	 *            the input context
	 * @return the suggestion result, never {@code null}
	 */
	AiSuggestionResult generateSuggestion(AiContext context);
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Optional;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;

/**
 * Manages registered {@link AiProvider} implementations and exposes the active
 * provider for the application.
 *
 * <p>
 * AI can be disabled globally via the {@code ai.enabled} property (default
 * {@code true}). When disabled, {@link #isAiEnabled()} returns {@code false}
 * and {@link #generateSuggestion(AiContext)} returns
 * {@link AiSuggestionResult#unavailable()} without calling any provider.
 *
 * <p>
 * Provider selection: the first registered provider that reports
 * {@link AiProvider#isAvailable()} is used. If none are available, the result
 * is also unavailable.
 */
@Component
public class AiProviderRegistry {

	private static final Logger log = LoggerFactory.getLogger(AiProviderRegistry.class);

	@Value("${ai.enabled:true}")
	private boolean aiEnabled;

	private final List<AiProvider> providers;

	public AiProviderRegistry(List<AiProvider> providers) {
		this.providers = providers != null ? providers : List.of();
	}

	/**
	 * Returns {@code true} when AI is enabled via feature flag AND at least one
	 * provider is registered.
	 */
	public boolean isAiEnabled() {
		return aiEnabled && !providers.isEmpty();
	}

	/**
	 * Returns the first registered provider that reports itself as available, or
	 * {@link Optional#empty()} if none are.
	 */
	public Optional<AiProvider> getActiveProvider() {
		if (!aiEnabled) {
			log.debug("AI is disabled via feature flag");
			return Optional.empty();
		}
		return providers.stream().filter(AiProvider::isAvailable).findFirst();
	}

	/**
	 * Convenience method: generates a suggestion using the active provider, or
	 * returns {@link AiSuggestionResult#unavailable()} with graceful degradation if
	 * the provider is unavailable or AI is disabled.
	 *
	 * <p>
	 * Core workflow is never affected — callers should check
	 * {@link AiSuggestionResult#available()} on the response.
	 *
	 * @param context
	 *            the input context
	 * @return suggestion result, never {@code null}
	 */
	public AiSuggestionResult generateSuggestion(AiContext context) {
		Optional<AiProvider> provider = getActiveProvider();
		if (provider.isEmpty()) {
			log.debug("No active AI provider; returning unavailable result for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}
		try {
			return provider.get().generateSuggestion(context);
		} catch (Exception ex) {
			log.warn("AI provider threw exception for type={}: {}", context.suggestionType(), ex.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// Visible for testing
	boolean isAiEnabledFlag() {
		return aiEnabled;
	}

	void setAiEnabled(boolean aiEnabled) {
		this.aiEnabled = aiEnabled;
	}
}

package com.weeklycommit.ai.provider;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicReference;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Component;

/**
 * Production AI provider that routes requests through OpenRouter.
 *
 * <p>
 * Activated when {@code ai.provider=openrouter} (the default). Falls back to
 * unavailable when the API key is blank or the service is unreachable.
 *
 * <p>
 * Features:
 * <ul>
 * <li>Per-suggestion-type prompt templates loaded from classpath</li>
 * <li>Cached health check (60 s TTL) to avoid hammering the API</li>
 * <li>Simple rate limiting via token-bucket (10 req/min default)</li>
 * <li>Token counting from response headers for cost tracking</li>
 * </ul>
 */
@Component
@ConditionalOnProperty(name = "ai.provider", havingValue = "openrouter", matchIfMissing = true)
public class OpenRouterAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(OpenRouterAiProvider.class);

	private final String apiKey;
	private final String model;
	private final int maxTokens;
	private final String baseUrl;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/** Cached availability result: [timestamp, available]. */
	private final AtomicReference<Instant> lastHealthCheck = new AtomicReference<>(Instant.EPOCH);
	private volatile boolean lastHealthResult = false;
	private static final Duration HEALTH_CACHE_TTL = Duration.ofSeconds(60);

	/** Simple rate limiter: track request count per minute window. */
	private final AtomicLong windowStart = new AtomicLong(System.currentTimeMillis());
	private final AtomicLong windowCount = new AtomicLong(0);
	private static final int MAX_REQUESTS_PER_MINUTE = 10;

	/** Running totals for observability. */
	private final AtomicLong totalTokensUsed = new AtomicLong(0);
	private final AtomicLong totalRequests = new AtomicLong(0);

	public OpenRouterAiProvider(@Value("${ai.openrouter.api-key:}") String apiKey,
			@Value("${ai.openrouter.model:anthropic/claude-sonnet-4-20250514}") String model,
			@Value("${ai.openrouter.max-tokens:1024}") int maxTokens,
			@Value("${ai.openrouter.base-url:https://openrouter.ai/api/v1}") String baseUrl,
			ObjectMapper objectMapper) {
		this.apiKey = apiKey;
		this.model = model;
		this.maxTokens = maxTokens;
		this.baseUrl = baseUrl;
		this.objectMapper = objectMapper;
		this.httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build();

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("OpenRouter API key is blank — provider will report unavailable");
		} else {
			log.info("OpenRouterAiProvider initialized: model={}, maxTokens={}", model, maxTokens);
		}
	}

	// ── AiProvider contract ──────────────────────────────────────────────

	@Override
	public String getName() {
		return "openrouter";
	}

	@Override
	public String getVersion() {
		return model;
	}

	@Override
	public boolean isAvailable() {
		if (apiKey == null || apiKey.isBlank()) {
			return false;
		}
		// Cached health check
		Instant now = Instant.now();
		if (Duration.between(lastHealthCheck.get(), now).compareTo(HEALTH_CACHE_TTL) < 0) {
			return lastHealthResult;
		}
		// Fresh check — just verify the API key works with a tiny request
		try {
			HttpRequest req = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/models"))
					.header("Authorization", "Bearer " + apiKey).timeout(Duration.ofSeconds(5)).GET().build();
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			lastHealthResult = resp.statusCode() == 200;
		} catch (Exception e) {
			log.debug("OpenRouter health check failed: {}", e.getMessage());
			lastHealthResult = false;
		}
		lastHealthCheck.set(now);
		return lastHealthResult;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		if (apiKey == null || apiKey.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// Rate limiting
		if (!tryAcquireRate()) {
			log.warn("OpenRouter rate limit exceeded for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		try {
			String systemPrompt = loadPromptTemplate(context.suggestionType());
			String userMessage = buildUserMessage(context);

			String responseBody = callOpenRouter(systemPrompt, userMessage);
			totalRequests.incrementAndGet();

			return parseResponse(responseBody, context.suggestionType());
		} catch (Exception e) {
			log.warn("OpenRouter request failed for type={}: {}", context.suggestionType(), e.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// ── HTTP call ────────────────────────────────────────────────────────

	private String callOpenRouter(String systemPrompt, String userMessage) throws IOException, InterruptedException {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("model", model);
		body.put("max_tokens", maxTokens);

		ArrayNode messages = body.putArray("messages");
		messages.addObject().put("role", "system").put("content", systemPrompt);
		messages.addObject().put("role", "user").put("content", userMessage);

		String json = objectMapper.writeValueAsString(body);

		HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/chat/completions"))
				.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
				.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
				.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

		if (response.statusCode() != 200) {
			throw new IOException("OpenRouter returned " + response.statusCode() + ": " + response.body());
		}

		// Track tokens from response
		try {
			JsonNode respNode = objectMapper.readTree(response.body());
			JsonNode usage = respNode.get("usage");
			if (usage != null && usage.has("total_tokens")) {
				totalTokensUsed.addAndGet(usage.get("total_tokens").asLong());
			}
		} catch (Exception ignored) {
		}

		return response.body();
	}

	// ── Response parsing ─────────────────────────────────────────────────

	private AiSuggestionResult parseResponse(String responseBody, String suggestionType) {
		try {
			JsonNode root = objectMapper.readTree(responseBody);
			JsonNode choices = root.get("choices");
			if (choices == null || choices.isEmpty()) {
				return AiSuggestionResult.unavailable();
			}

			String content = choices.get(0).path("message").path("content").asText("");
			if (content.isBlank()) {
				return AiSuggestionResult.unavailable();
			}

			// The model should return JSON. Extract it — handle markdown code fences.
			String jsonPayload = extractJson(content);
			String rationale = extractRationale(content, jsonPayload);

			// Validate it's parseable JSON
			objectMapper.readTree(jsonPayload);

			return new AiSuggestionResult(true, jsonPayload, rationale, 0.85, model);
		} catch (Exception e) {
			log.warn("Failed to parse OpenRouter response for {}: {}", suggestionType, e.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// ── Prompt construction ──────────────────────────────────────────────

	private String loadPromptTemplate(String suggestionType) {
		String filename = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist.txt";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint.txt";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest.txt";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal.txt";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist.txt";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary.txt";
			default -> "generic.txt";
		};
		try {
			ClassPathResource resource = new ClassPathResource("prompts/" + filename);
			return new String(resource.getInputStream().readAllBytes());
		} catch (IOException e) {
			log.debug("Prompt template not found: prompts/{}, using default", filename);
			return "You are a helpful planning assistant for a weekly commitment tool. "
					+ "Respond with valid JSON matching the expected schema.";
		}
	}

	private String buildUserMessage(AiContext context) {
		try {
			Map<String, Object> msg = Map.of("suggestionType", context.suggestionType(), "commitData",
					context.commitData() != null ? context.commitData() : Map.of(), "planData",
					context.planData() != null ? context.planData() : Map.of(), "historicalCommits",
					context.historicalCommits() != null ? context.historicalCommits() : java.util.List.of(), "rcdoTree",
					context.rcdoTree() != null ? context.rcdoTree() : java.util.List.of(), "additionalContext",
					context.additionalContext() != null ? context.additionalContext() : Map.of());
			return objectMapper.writeValueAsString(msg);
		} catch (Exception e) {
			return "{}";
		}
	}

	// ── Helpers ──────────────────────────────────────────────────────────

	/**
	 * Extracts JSON from model output, handling ```json fences.
	 */
	private String extractJson(String content) {
		String trimmed = content.trim();
		// Handle ```json ... ``` fences
		if (trimmed.contains("```json")) {
			int start = trimmed.indexOf("```json") + 7;
			int end = trimmed.indexOf("```", start);
			if (end > start) {
				return trimmed.substring(start, end).trim();
			}
		}
		if (trimmed.contains("```")) {
			int start = trimmed.indexOf("```") + 3;
			// Skip optional language identifier on the same line
			int lineEnd = trimmed.indexOf('\n', start);
			if (lineEnd > start) {
				start = lineEnd + 1;
			}
			int end = trimmed.indexOf("```", start);
			if (end > start) {
				return trimmed.substring(start, end).trim();
			}
		}
		// Try to find raw JSON object
		int braceStart = trimmed.indexOf('{');
		int braceEnd = trimmed.lastIndexOf('}');
		if (braceStart >= 0 && braceEnd > braceStart) {
			return trimmed.substring(braceStart, braceEnd + 1);
		}
		return trimmed;
	}

	private String extractRationale(String fullContent, String jsonPayload) {
		// Everything outside the JSON is rationale
		String without = fullContent.replace(jsonPayload, "").trim();
		// Strip markdown fences
		without = without.replaceAll("```json\\s*", "").replaceAll("```\\s*", "").trim();
		return without.isBlank() ? "AI-generated suggestion" : without.substring(0, Math.min(500, without.length()));
	}

	private boolean tryAcquireRate() {
		long now = System.currentTimeMillis();
		long windowMs = 60_000;
		if (now - windowStart.get() > windowMs) {
			windowStart.set(now);
			windowCount.set(0);
		}
		return windowCount.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
	}

	// ── Observability ────────────────────────────────────────────────────

	/** Total tokens consumed across all requests (for metrics). */
	public long getTotalTokensUsed() {
		return totalTokensUsed.get();
	}

	/** Total requests made (for metrics). */
	public long getTotalRequests() {
		return totalRequests.get();
	}
}

package com.weeklycommit.ai.service;

import com.weeklycommit.ai.dto.AiFeedbackRequest;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiFeedback;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.repository.AiFeedbackRepository;
import com.weeklycommit.domain.repository.AiSuggestionRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.HexFormat;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Handles storage and retrieval of {@link AiSuggestion} records and
 * {@link AiFeedback} records.
 */
@Service
@Transactional
public class AiSuggestionService {

	private static final Logger log = LoggerFactory.getLogger(AiSuggestionService.class);

	private final AiSuggestionRepository suggestionRepo;
	private final AiFeedbackRepository feedbackRepo;

	public AiSuggestionService(AiSuggestionRepository suggestionRepo, AiFeedbackRepository feedbackRepo) {
		this.suggestionRepo = suggestionRepo;
		this.feedbackRepo = feedbackRepo;
	}

	/**
	 * Persists an {@link AiSuggestion} record for audit and feedback purposes.
	 *
	 * @param suggestionType
	 *            type discriminator (see
	 *            {@link com.weeklycommit.ai.provider.AiContext} constants)
	 * @param userId
	 *            requesting user
	 * @param planId
	 *            associated plan, may be null
	 * @param commitId
	 *            associated commit, may be null
	 * @param contextString
	 *            the serialised context used to produce the suggestion
	 * @param result
	 *            the provider result
	 * @return the persisted {@link AiSuggestion}
	 */
	public AiSuggestion storeSuggestion(String suggestionType, UUID userId, UUID planId, UUID commitId,
			String contextString, AiSuggestionResult result) {
		AiSuggestion s = new AiSuggestion();
		s.setSuggestionType(suggestionType);
		s.setUserId(userId);
		s.setPlanId(planId);
		s.setCommitId(commitId);
		s.setPrompt(contextString != null ? contextString : "{}");
		s.setContextHash(hash(contextString));
		s.setRationale(result.rationale());
		s.setSuggestionPayload(result.payload());
		s.setModelVersion(result.modelVersion());
		return suggestionRepo.save(s);
	}

	/**
	 * Records user feedback on a suggestion.
	 *
	 * @param request
	 *            the feedback request
	 * @return the saved {@link AiFeedback}
	 * @throws ResourceNotFoundException
	 *             if the suggestion does not exist
	 */
	public AiFeedback recordFeedback(AiFeedbackRequest request) {
		if (!suggestionRepo.existsById(request.suggestionId())) {
			throw new ResourceNotFoundException("AI suggestion not found: " + request.suggestionId());
		}

		AiFeedback feedback = new AiFeedback();
		feedback.setSuggestionId(request.suggestionId());
		feedback.setUserId(request.userId());
		feedback.setAccepted(request.action() != AiFeedbackRequest.FeedbackAction.DISMISSED);
		feedback.setFeedbackNotes(request.notes());
		AiFeedback saved = feedbackRepo.save(feedback);

		// Also update the suggestion's accepted/dismissed flags for quick reads
		suggestionRepo.findById(request.suggestionId()).ifPresent(s -> {
			switch (request.action()) {
				case ACCEPTED, EDITED -> s.setAccepted(true);
				case DISMISSED -> s.setDismissed(true);
			}
			suggestionRepo.save(s);
		});

		log.debug("Recorded AI feedback: suggestionId={}, action={}", request.suggestionId(), request.action());
		return saved;
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	static String hash(String input) {
		if (input == null || input.isBlank()) {
			return "";
		}
		try {
			MessageDigest digest = MessageDigest.getInstance("SHA-256");
			byte[] bytes = digest.digest(input.getBytes(StandardCharsets.UTF_8));
			return HexFormat.of().formatHex(bytes);
		} catch (NoSuchAlgorithmException e) {
			log.warn("SHA-256 not available; using empty hash");
			return "";
		}
	}
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Map;
import java.util.UUID;

/**
 * Input context supplied to an {@link AiProvider} when requesting a suggestion.
 * All fields are optional except {@code suggestionType}.
 */
public record AiContext(
		/** Discriminator for the kind of suggestion being requested. */
		String suggestionType,
		/** Requesting user (for personalisation and audit). */
		UUID userId,
		/** Plan being analysed, if applicable. */
		UUID planId,
		/** Specific commit being analysed, if applicable. */
		UUID commitId,
		/** Serialised current commit fields (title, chessPiece, etc.). */
		Map<String, Object> commitData,
		/** Serialised plan summary (state, capacity, etc.). */
		Map<String, Object> planData,
		/** Recent historical commits for pattern matching. */
		List<Map<String, Object>> historicalCommits,
		/** Relevant RCDO tree nodes. */
		List<Map<String, Object>> rcdoTree,
		/** Free-form additional context (e.g., scope changes, risk inputs). */
		Map<String, Object> additionalContext) {

	/** Suggestion type constant — commit draft assistance. */
	public static final String TYPE_COMMIT_DRAFT = "COMMIT_DRAFT_ASSIST";

	/** Suggestion type constant — commit quality lint. */
	public static final String TYPE_COMMIT_LINT = "COMMIT_LINT";

	/** Suggestion type constant — RCDO link suggestion. */
	public static final String TYPE_RCDO_SUGGEST = "RCDO_SUGGEST";

	/** Suggestion type constant — risk signal detection. */
	public static final String TYPE_RISK_SIGNAL = "RISK_SIGNAL";

	/** Suggestion type constant — reconciliation assistance. */
	public static final String TYPE_RECONCILE_ASSIST = "RECONCILE_ASSIST";

	/** Suggestion type constant — team manager AI summary. */
	public static final String TYPE_TEAM_SUMMARY = "TEAM_SUMMARY";
}

package com.weeklycommit.ai.provider;

/**
 * Result returned by an {@link AiProvider}.
 *
 * <p>
 * When {@code available} is {@code false}, all other fields are meaningless and
 * callers should propagate {@code aiAvailable: false} to their response without
 * failing the request.
 */
public record AiSuggestionResult(
		/** {@code false} when the provider is down or AI is disabled. */
		boolean available,
		/**
		 * JSON-serialised suggestion payload. Structure varies by
		 * {@link AiContext#suggestionType()}.
		 */
		String payload,
		/** Human-readable rationale explaining why the suggestion was made. */
		String rationale,
		/**
		 * Provider confidence in the primary suggestion [0.0, 1.0]. Used for RCDO
		 * suggestions to filter below the surfacing threshold.
		 */
		double confidence,
		/** Provider model identifier for audit and reproducibility. */
		String modelVersion) {

	/** Convenience factory for an unavailable (degraded) result. */
	public static AiSuggestionResult unavailable() {
		return new AiSuggestionResult(false, "{}", "AI provider unavailable", 0.0, "none");
	}
}

package com.weeklycommit.ai.provider;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

/**
 * Development/test stub implementation of {@link AiProvider}.
 *
 * <p>
 * Returns deterministic canned responses for every suggestion type so the rest
 * of the AI pipeline can be tested end-to-end without a real model. Always
 * reports itself as available.
 */
@Component
@org.springframework.boot.autoconfigure.condition.ConditionalOnProperty(name = "ai.provider", havingValue = "stub")
public class StubAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(StubAiProvider.class);

	static final String STUB_MODEL_VERSION = "stub-v1";

	@Override
	public String getName() {
		return "stub";
	}

	@Override
	public String getVersion() {
		return STUB_MODEL_VERSION;
	}

	@Override
	public boolean isAvailable() {
		return true;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		log.debug("StubAiProvider.generateSuggestion: type={}", context.suggestionType());
		String payload;
		String rationale;
		double confidence = 0.85;

		switch (context.suggestionType()) {
			case AiContext.TYPE_COMMIT_DRAFT -> {
				payload = """
						{
						  "suggestedTitle": "Implement feature with clear acceptance criteria",
						  "suggestedDescription": "Break this commit into smaller, measurable deliverables.",
						  "suggestedSuccessCriteria": "Feature is deployed and passing all tests.",
						  "suggestedEstimatePoints": 3
						}
						""";
				rationale = "Commit title appears vague; similar past commits used more specific language.";
			}
			case AiContext.TYPE_COMMIT_LINT -> {
				payload = """
						{
						  "hardValidation": [],
						  "softGuidance": [
						    {
						      "code": "VAGUE_TITLE",
						      "message": "Consider making the title more specific and outcome-focused."
						    }
						  ]
						}
						""";
				rationale = "Commit title could be more specific. No hard violations detected.";
				confidence = 0.9;
			}
			case AiContext.TYPE_RCDO_SUGGEST -> {
				Object rcdoList = context.rcdoTree() != null && !context.rcdoTree().isEmpty()
						? context.rcdoTree().get(0).get("id")
						: null;
				payload = String.format("""
						{
						  "suggestedRcdoNodeId": "%s",
						  "confidence": 0.85
						}
						""", rcdoList != null ? rcdoList : "");
				rationale = "Commit title and description closely match this Outcome's scope.";
				confidence = 0.85;
			}
			case AiContext.TYPE_RISK_SIGNAL -> {
				payload = """
						{
						  "signals": []
						}
						""";
				rationale = "No risk signals detected for this plan.";
				confidence = 0.95;
			}
			case AiContext.TYPE_RECONCILE_ASSIST -> {
				payload = """
						{
						  "likelyOutcomes": [],
						  "draftSummary": "Plan reconciliation appears straightforward with no major deviations.",
						  "carryForwardRecommendations": []
						}
						""";
				rationale = "No unresolved commits detected that require carry-forward.";
			}
			case AiContext.TYPE_TEAM_SUMMARY -> {
				payload = """
						{
						  "summaryText": "Team plan looks healthy this week.",
						  "topRcdoBranches": [],
						  "carryForwardPatterns": [],
						  "criticalBlockedItemIds": []
						}
						""";
				rationale = "Generated from team plan data for the requested week.";
			}
			default -> {
				payload = "{}";
				rationale = "Unknown suggestion type.";
				confidence = 0.0;
			}
		}

		return new AiSuggestionResult(true, payload.trim(), rationale, confidence, STUB_MODEL_VERSION);
	}
}

