/**
 * AI API client functions for all AI-powered endpoints.
 */
import type { ApiClient } from "./client.js";

// ── Types ─────────────────────────────────────────────────────────────────────

export interface AiStatusResponse {
  aiEnabled: boolean;
  providerName: string;
  providerVersion: string;
  available: boolean;
}

export interface CommitDraftAssistRequest {
  userId: string;
  planId: string;
  commitId?: string;
  currentTitle: string;
  currentDescription?: string;
  currentSuccessCriteria?: string;
  currentEstimatePoints?: number;
  chessPiece?: string;
}

export interface CommitDraftAssistResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  suggestedTitle?: string | null;
  suggestedDescription?: string | null;
  suggestedSuccessCriteria?: string | null;
  suggestedEstimatePoints?: number | null;
  rationale?: string;
}

export interface CommitLintRequest {
  userId: string;
  planId: string;
}

export interface LintMessage {
  code: string;
  message: string;
  commitId?: string;
}

export interface CommitLintResponse {
  aiAvailable: boolean;
  suggestionId?: string;
  hardValidation: LintMessage[];
  softGuidance: LintMessage[];
  rationale?: string;
}

export interface RiskSignal {
  id: string;
  signalType: string;
  rationale: string;
  planId: string;
  commitId?: string | null;
  createdAt: string;
}

export interface PlanRiskSignalsResponse {
  aiAvailable: boolean;
  planId: string;
  signals: RiskSignal[];
}

export type FeedbackAction = "ACCEPTED" | "DISMISSED" | "EDITED";

export interface AiFeedbackRequest {
  suggestionId: string;
  userId: string;
  action: FeedbackAction;
  notes?: string;
}

// ── API factory ───────────────────────────────────────────────────────────────

export function createAiApi(client: ApiClient, actorUserId: string) {
  const actorHeader = { "X-Actor-User-Id": actorUserId };

  return {
    /** GET /api/ai/status — provider health/availability check. */
    getStatus: (): Promise<AiStatusResponse> =>
      client.get("/ai/status"),

    /** POST /api/ai/commit-draft-assist — get draft improvement suggestions. */
    commitDraftAssist: (
      request: CommitDraftAssistRequest,
    ): Promise<CommitDraftAssistResponse> =>
      client.post("/ai/commit-draft-assist", request),

    /** POST /api/ai/commit-lint — run commit quality lint on a plan. */
    commitLint: (request: CommitLintRequest): Promise<CommitLintResponse> =>
      client.post("/ai/commit-lint", request),

    /** GET /api/plans/{id}/risk-signals — risk signals for a plan. */
    getRiskSignals: (planId: string): Promise<PlanRiskSignalsResponse> =>
      client.get(`/plans/${encodeURIComponent(planId)}/risk-signals`, {
        headers: actorHeader,
      }),

    /** POST /api/ai/feedback — record thumbs up/down on a suggestion. */
    recordFeedback: (request: AiFeedbackRequest): Promise<void> =>
      client.post("/ai/feedback", request),
  };
}

export type AiApi = ReturnType<typeof createAiApi>;

/**
 * React hooks for AI API endpoints.
 */
import { useMemo } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import { createAiApi, type AiApi, type AiStatusResponse, type PlanRiskSignalsResponse } from "./aiApi.js";

/** Returns a stable AiApi instance bound to the current user's auth token. */
export function useAiApi(): AiApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createAiApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

/** Fetches the AI provider status. */
export function useAiStatus(): QueryState<AiStatusResponse> {
  const api = useAiApi();
  return useQuery<AiStatusResponse>("ai-status", () => api.getStatus());
}

/** Fetches risk signals for a specific plan. */
export function useRiskSignals(
  planId: string | null,
): QueryState<PlanRiskSignalsResponse> {
  const api = useAiApi();
  return useQuery<PlanRiskSignalsResponse>(
    `risk-signals-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getRiskSignals(planId);
    },
    { enabled: planId != null },
  );
}

/**
 * Typed API client for the Weekly Commit Module backend.
 * Injects the host-supplied auth token on every request.
 */

export interface ApiError {
  readonly status: number;
  readonly message: string;
  readonly details?: unknown;
}

export class ApiRequestError extends Error {
  readonly status: number;
  readonly details?: unknown;

  constructor(error: ApiError) {
    super(error.message);
    this.name = "ApiRequestError";
    this.status = error.status;
    this.details = error.details;
  }
}

export interface RequestOptions {
  readonly method?: "GET" | "POST" | "PUT" | "PATCH" | "DELETE";
  readonly body?: unknown;
  readonly headers?: Record<string, string>;
  /** Milliseconds before the request times out (default: 30_000). */
  readonly timeoutMs?: number;
}

export interface ApiClientConfig {
  readonly baseUrl: string;
  /** Returns the current auth token (may change between calls). */
  getAuthToken(): string;
}

/**
 * Creates a typed API client bound to the given base URL and auth provider.
 * All errors are normalized to {@link ApiRequestError}.
 */
export function createApiClient(config: ApiClientConfig) {
  async function request<T>(
    path: string,
    options: RequestOptions = {},
  ): Promise<T> {
    const { method = "GET", body, headers = {}, timeoutMs = 30_000 } = options;

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

    const requestHeaders: Record<string, string> = {
      "Content-Type": "application/json",
      Authorization: `Bearer ${config.getAuthToken()}`,
      ...headers,
    };

    try {
      const fetchInit: RequestInit = {
        method,
        headers: requestHeaders,
        signal: controller.signal,
      };
      if (body !== undefined) {
        fetchInit.body = JSON.stringify(body);
      }
      const response = await fetch(`${config.baseUrl}${path}`, fetchInit);

      if (!response.ok) {
        let errorDetails: unknown;
        try {
          errorDetails = await response.json();
        } catch {
          errorDetails = undefined;
        }
        throw new ApiRequestError({
          status: response.status,
          message: `API request failed: ${response.status} ${response.statusText}`,
          details: errorDetails,
        });
      }

      // 204 No Content → return undefined cast to T
      if (response.status === 204) {
        return undefined as T;
      }

      return (await response.json()) as T;
    } catch (err) {
      if (err instanceof ApiRequestError) {
        throw err;
      }
      if (err instanceof DOMException && err.name === "AbortError") {
        throw new ApiRequestError({
          status: 408,
          message: "Request timed out",
        });
      }
      throw new ApiRequestError({
        status: 0,
        message: err instanceof Error ? err.message : "Network error",
      });
    } finally {
      clearTimeout(timeoutId);
    }
  }

  return {
    get<T>(path: string, options?: Omit<RequestOptions, "method" | "body">) {
      return request<T>(path, { ...options, method: "GET" });
    },
    post<T>(
      path: string,
      body: unknown,
      options?: Omit<RequestOptions, "method" | "body">,
    ) {
      return request<T>(path, { ...options, method: "POST", body });
    },
    put<T>(
      path: string,
      body: unknown,
      options?: Omit<RequestOptions, "method" | "body">,
    ) {
      return request<T>(path, { ...options, method: "PUT", body });
    },
    patch<T>(
      path: string,
      body: unknown,
      options?: Omit<RequestOptions, "method" | "body">,
    ) {
      return request<T>(path, { ...options, method: "PATCH", body });
    },
    delete<T>(path: string, options?: Omit<RequestOptions, "method" | "body">) {
      return request<T>(path, { ...options, method: "DELETE" });
    },
  };
}

export type ApiClient = ReturnType<typeof createApiClient>;

/**
 * Lightweight data-fetching hooks following a useQuery pattern.
 * Wraps the API client with loading and error state management.
 */

import { useState, useEffect, useCallback, useRef } from "react";
import { ApiRequestError } from "./client.js";

export interface QueryState<T> {
  readonly data: T | undefined;
  readonly loading: boolean;
  readonly error: ApiRequestError | null;
  /** Re-trigger the query. */
  refetch(): void;
}

/**
 * Executes an async fetcher and manages loading/error/data state.
 * Re-runs whenever the `key` string changes.
 *
 * @param key     Cache/identity key. Change it to re-run the query.
 * @param fetcher Async function returning the data.
 */
export function useQuery<T>(
  key: string,
  fetcher: () => Promise<T>,
  options?: { enabled?: boolean },
): QueryState<T> {
  const [data, setData] = useState<T | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<ApiRequestError | null>(null);
  const [revision, setRevision] = useState(0);
  const enabled = options?.enabled ?? true;

  // Keep a stable ref to the fetcher so the effect dep array stays clean
  const fetcherRef = useRef(fetcher);
  fetcherRef.current = fetcher;

  useEffect(() => {
    if (!enabled) {
      setData(undefined);
      setLoading(false);
      setError(null);
      return;
    }

    let cancelled = false;
    setLoading(true);
    setError(null);

    fetcherRef
      .current()
      .then((result) => {
        if (!cancelled) {
          setData(result);
          setLoading(false);
        }
      })
      .catch((err: unknown) => {
        if (!cancelled) {
          if (err instanceof ApiRequestError) {
            setError(err);
          } else {
            setError(
              new ApiRequestError({ status: 0, message: "Unexpected error" }),
            );
          }
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [enabled, key, revision]);

  const refetch = useCallback(() => {
    setRevision((r) => r + 1);
  }, []);

  return { data, loading, error, refetch };
}

/**
 * Thumbs up / thumbs down feedback buttons for AI suggestions.
 * Records feedback via POST /api/ai/feedback.
 */
import { useState, useCallback } from "react";
import { ThumbsUp, ThumbsDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { FeedbackAction } from "../../api/aiApi.js";

interface AiFeedbackButtonsProps {
  suggestionId: string;
  className?: string;
}

export function AiFeedbackButtons({ suggestionId, className }: AiFeedbackButtonsProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const [submitted, setSubmitted] = useState<FeedbackAction | null>(null);

  const handleFeedback = useCallback(
    async (action: FeedbackAction) => {
      try {
        await aiApi.recordFeedback({ suggestionId, userId, action });
        setSubmitted(action);
      } catch {
        // Non-critical — don't block the UI
      }
    },
    [aiApi, suggestionId, userId],
  );

  if (submitted) {
    return (
      <span className={cn("text-xs text-muted italic", className)}>
        {submitted === "ACCEPTED" ? "Thanks! 👍" : "Noted 👎"}
      </span>
    );
  }

  return (
    <span className={cn("inline-flex gap-1", className)}>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("ACCEPTED")}
        aria-label="Helpful suggestion"
        className="h-6 w-6 text-muted hover:text-success"
        data-testid="ai-feedback-accept"
      >
        <ThumbsUp className="h-3.5 w-3.5" />
      </Button>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("DISMISSED")}
        aria-label="Not helpful"
        className="h-6 w-6 text-muted hover:text-danger"
        data-testid="ai-feedback-dismiss"
      >
        <ThumbsDown className="h-3.5 w-3.5" />
      </Button>
    </span>
  );
}

/**
 * My Week — personal weekly plan view.
 * Route: /weekly/my-week
 */
import { useState, useCallback, useMemo } from "react";
import { ChevronLeft, ChevronRight, Lock, AlertTriangle, Check, X } from "lucide-react";
import { Button } from "../components/ui/Button.js";
import { Badge } from "../components/ui/Badge.js";
import { Card, CardHeader, CardTitle, CardContent } from "../components/ui/Card.js";
import { Dialog, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "../components/ui/Dialog.js";
import { useCurrentPlan, usePlanApi } from "../api/planHooks.js";
import { useRcdoTree } from "../api/rcdoHooks.js";
import { usePlanHistory, useCarryForwardLineage, useTicketApi } from "../api/ticketHooks.js";
import { PlanHistoryView } from "../components/myweek/PlanHistoryView.js";
import { CarryForwardLineageView } from "../components/myweek/CarryForwardLineageView.js";
import { TicketForm } from "../components/tickets/TicketForm.js";
import { useHostBridge } from "../host/HostProvider.js";
import type { CreateTicketPayload } from "../api/ticketTypes.js";
import { CommitList } from "../components/myweek/CommitList.js";
import { CommitForm } from "../components/myweek/CommitForm.js";
import { CapacityMeter } from "../components/myweek/CapacityMeter.js";
import { SoftWarningsPanel } from "../components/myweek/SoftWarningsPanel.js";
import { PreLockValidationPanel } from "../components/lock/PreLockValidationPanel.js";
import { LockConfirmDialog } from "../components/lock/LockConfirmDialog.js";
import { ScopeChangeDialog } from "../components/lock/ScopeChangeDialog.js";
import { ScopeChangeTimeline } from "../components/lock/ScopeChangeTimeline.js";
import { getEffectivePreLockErrors } from "../components/lock/lockValidation.js";
