/**
 * AI commit lint panel — replaces the placeholder in PreLockValidationPanel.
 * Calls POST /api/ai/commit-lint and displays hard + soft lint messages
 * with feedback buttons on each.
 */
import { useState, useCallback } from "react";
import { Bot, RefreshCw } from "lucide-react";
import { Button } from "../ui/Button.js";
import { AiFeedbackButtons } from "./AiFeedbackButtons.js";
import { useAiApi, useAiStatus } from "../../api/aiHooks.js";
import type { CommitLintResponse } from "../../api/aiApi.js";

interface AiLintPanelProps {
  planId: string;
  userId: string;
}

export function AiLintPanel({ planId, userId }: AiLintPanelProps) {
  const aiApi = useAiApi();
  const { data: status } = useAiStatus();
  const [lintResult, setLintResult] = useState<CommitLintResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const runLint = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const result = await aiApi.commitLint({ userId, planId });
      setLintResult(result);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Lint failed");
    } finally {
      setLoading(false);
    }
  }, [aiApi, planId, userId]);

  // AI not available — show disabled state
  if (status && !status.available) {
    return (
      <div className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 shrink-0" aria-hidden="true" />
        AI commit quality hints unavailable ({status.providerName})
      </div>
    );
  }

  // Not yet run
  if (!lintResult && !loading) {
    return (
      <div className="flex items-center gap-2" data-testid="ai-lint-ready">
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-7 text-xs border border-dashed border-border" data-testid="ai-lint-run-btn">
          <Bot className="h-3.5 w-3.5" />
          Run AI Quality Check
        </Button>
      </div>
    );
  }

  // Loading
  if (loading) {
    return (
      <div className="flex items-center gap-2 text-xs text-muted animate-pulse" data-testid="ai-lint-loading">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        Analyzing commit quality…
      </div>
    );
  }

  // Error
  if (error) {
    return (
      <div className="flex items-center gap-2 text-xs text-danger" data-testid="ai-lint-error">
        <Bot className="h-3.5 w-3.5 shrink-0" />
        {error}
        <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs">
          <RefreshCw className="h-3 w-3" />Retry
        </Button>
      </div>
    );
  }

  // Results
  if (!lintResult?.aiAvailable) {
    return (
      <div className="text-xs text-muted italic" data-testid="ai-lint-unavailable">
        <Bot className="h-3.5 w-3.5 inline mr-1" />AI lint unavailable
      </div>
    );
  }

  const hasHard = lintResult.hardValidation.length > 0;
  const hasSoft = lintResult.softGuidance.length > 0;

  return (
    <div className="flex flex-col gap-2" data-testid="ai-lint-results">
      {/* Header with refresh */}
      <div className="flex items-center justify-between">
        <span className="flex items-center gap-1.5 text-xs font-semibold text-muted">
          <Bot className="h-3.5 w-3.5" />AI Quality Check
        </span>
        <div className="flex items-center gap-1.5">
          {lintResult.suggestionId && <AiFeedbackButtons suggestionId={lintResult.suggestionId} />}
          <Button variant="ghost" size="sm" onClick={() => void runLint()} className="h-6 text-xs" data-testid="ai-lint-refresh">
            <RefreshCw className="h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Hard validations */}
      {hasHard && (
        <div className="rounded-sm border border-red-200 bg-red-50 px-3 py-2" data-testid="ai-lint-hard">
          <p className="m-0 mb-1 text-xs font-semibold text-red-800">Hard Issues</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.hardValidation.map((msg, i) => (
              <li key={i} className="text-xs text-red-700">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* Soft guidance */}
      {hasSoft && (
        <div className="rounded-sm border border-amber-200 bg-amber-50 px-3 py-2" data-testid="ai-lint-soft">
          <p className="m-0 mb-1 text-xs font-semibold text-amber-800">Suggestions</p>
          <ul className="m-0 pl-4 flex flex-col gap-0.5">
            {lintResult.softGuidance.map((msg, i) => (
              <li key={i} className="text-xs text-amber-700">{msg.message}</li>
            ))}
          </ul>
        </div>
      )}

      {/* All clear */}
      {!hasHard && !hasSoft && (
        <div className="text-xs text-success flex items-center gap-1" data-testid="ai-lint-clear">
          ✓ No quality issues detected
        </div>
      )}
    </div>
  );
}

/**
 * Risk signals panel — displays AI-detected and rules-based risk signals
 * for a plan. Used on the Team Week page's risk tab.
 */
import { AlertTriangle, ShieldAlert, TrendingDown, RotateCcw, Zap, Activity } from "lucide-react";
import { Badge } from "../ui/Badge.js";
import { Skeleton } from "../ui/Skeleton.js";
import { cn } from "../../lib/utils.js";
import { useRiskSignals } from "../../api/aiHooks.js";
import type { RiskSignal } from "../../api/aiApi.js";

const SIGNAL_ICONS: Record<string, typeof AlertTriangle> = {
  OVERCOMMIT: TrendingDown,
  UNDERCOMMIT: TrendingDown,
  REPEATED_CARRY_FORWARD: RotateCcw,
  BLOCKED_CRITICAL: ShieldAlert,
  SCOPE_VOLATILITY: Zap,
};

const SIGNAL_CLS: Record<string, string> = {
  OVERCOMMIT: "border-red-200 bg-red-50 text-red-800",
  UNDERCOMMIT: "border-amber-200 bg-amber-50 text-amber-800",
  REPEATED_CARRY_FORWARD: "border-blue-200 bg-blue-50 text-blue-800",
  BLOCKED_CRITICAL: "border-red-200 bg-red-50 text-red-800",
  SCOPE_VOLATILITY: "border-violet-200 bg-violet-50 text-violet-800",
};

function SignalCard({ signal }: { signal: RiskSignal }) {
  const Icon = SIGNAL_ICONS[signal.signalType] ?? Activity;
  const cls = SIGNAL_CLS[signal.signalType] ?? "border-border bg-background text-foreground";

  return (
    <div className={cn("rounded-default border px-3 py-2.5 flex items-start gap-2.5", cls)} data-testid={`risk-signal-${signal.id}`}>
      <Icon className="h-4 w-4 mt-0.5 shrink-0" aria-hidden="true" />
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-1">
          <Badge variant="default" className="text-[0.6rem]">{signal.signalType}</Badge>
          <span className="text-[0.65rem] text-muted">
            {new Date(signal.createdAt).toLocaleDateString()}
          </span>
        </div>
        <p className="m-0 text-xs">{signal.rationale}</p>
      </div>
    </div>
  );
}

interface RiskSignalsPanelProps {
  planId: string | null;
}

export function RiskSignalsPanel({ planId }: RiskSignalsPanelProps) {
  const { data, loading, error } = useRiskSignals(planId);

  if (!planId) {
    return (
      <div className="text-sm text-muted py-4 text-center" data-testid="risk-signals-no-plan">
        Select a member's plan to view risk signals.
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex flex-col gap-2" data-testid="risk-signals-loading">
        <Skeleton className="h-16 w-full" />
        <Skeleton className="h-16 w-full" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-sm text-danger" data-testid="risk-signals-error">
        Failed to load risk signals: {error.message}
      </div>
    );
  }

  if (!data?.aiAvailable) {
    return (
      <div className="text-sm text-muted italic" data-testid="risk-signals-unavailable">
        Risk detection is currently unavailable.
      </div>
    );
  }

  if (data.signals.length === 0) {
    return (
      <div className="flex items-center gap-2 text-sm text-success py-4" data-testid="risk-signals-clear">
        <ShieldAlert className="h-4 w-4" />
        No risk signals detected for this plan.
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-2" data-testid="risk-signals-list">
      <div className="flex items-center justify-between">
        <span className="text-xs font-semibold text-muted uppercase tracking-wider">
          {data.signals.length} Risk Signal{data.signals.length !== 1 ? "s" : ""}
        </span>
      </div>
      {data.signals.map((signal) => (
        <SignalCard key={signal.id} signal={signal} />
      ))}
    </div>
  );
}

